import{_ as d,c as t,a2 as c,G as e,B as o,o as n}from"./chunks/framework.DUe8d0tq.js";const f=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"update/v1.0.4-230608.md","filePath":"update/v1.0.4-230608.md"}'),s={name:"update/v1.0.4-230608.md"};function r(p,a,u,h,g,b){const i=o("NolebaseGitContributors"),l=o("NolebaseGitChangelog");return n(),t("div",null,[a[0]||(a[0]=c('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>日期：2023 年 06 月 08 日<br> 版本：v1.0.4<br> 描述：新增文章详情页面原文链接功能、文章详情设置密码功能、文章详情设置部分内容加密、优化部分内容。</p><h2 id="更新内容" tabindex="-1">更新内容 <a class="header-anchor" href="#更新内容" aria-label="Permalink to &quot;更新内容&quot;">​</a></h2><ul><li><p>新增：文章详情原文地址元数据参数 <code>unihalo_originalURL</code>，经过测试个人资质小程序可以打开公众号链接（非常适用），其他链接不行，非个人资质都可以；</p></li><li><p>新增：文章详情全部加密，元数据参数 <code>unihalo_useVisitPwd</code>，设置该参数后，进入详情页面会直接弹出密码验证提示框，输入正确的密码才可以显示文章内容；</p></li><li><p>新增：文章详情部分内容加密，元数据参数 <code>unihalo_useVisitMorePwd</code>，，设置该参数后，进入详情页面不会主动弹出密码验证输入框，但是只会显示一部分文章内容，需要用户手动点击弹窗输入密码验证后才可以查看完整的文章内容（后续可以作为查看广告后看完整内容）；</p></li><li><p>优化：对所有列表动画效果进行优化；</p></li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><ul><li><p>新增加的功能，不会对 PC 端的 Halo 博客产生任何影响，除非您自己去适配，否则以上的内容只会在 <code>uni-halo</code> 程序中生效。</p></li><li><p>新增的 <code>文章加密访问（unihalo_useVisitPwd）</code> 和 <code>文章部分加密（unihalo_useVisitMorePwd）</code> 不会同时生效，如果两个同时设置，优先启用 <code>文章加密访问（unihalo_useVisitPwd）</code> 的方式。</p></li></ul></div><h2 id="更新功能" tabindex="-1">更新功能 <a class="header-anchor" href="#更新功能" aria-label="Permalink to &quot;更新功能&quot;">​</a></h2><h3 id="_1-原文链接-unihalo-originalurl" tabindex="-1">1. 原文链接：<code>unihalo_originalURL</code> <a class="header-anchor" href="#_1-原文链接-unihalo-originalurl" aria-label="Permalink to &quot;1. 原文链接：`unihalo_originalURL`&quot;">​</a></h3><p>使用方式：在 Halo 博客后台，发布文章的时候，选择 <code>元数据</code> 新增元数据 key 值为 <code>unihalo_originalURL</code> 并填入文章 url 地址，如： <code>https://blog.xiaoxiaomo.cn/archives/233.html</code>，如图所示：</p><p><img src="https://img.925i.cn/file/4db9fc97a66476a5fc831.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><p><img src="https://img.925i.cn/file/3b9fbd009e8e75c55c2c1.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><p>即可在 <code>uni-halo</code> 应用内的文章详情页面看到相关链接，如图所示：</p><p><img src="https://img.925i.cn/file/fd5d9708b1721b4dbbb8f.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><h3 id="_2-文章加密访问-unihalo-usevisitpwd" tabindex="-1">2. 文章加密访问：<code>unihalo_useVisitPwd</code> <a class="header-anchor" href="#_2-文章加密访问-unihalo-usevisitpwd" aria-label="Permalink to &quot;2. 文章加密访问：`unihalo_useVisitPwd`&quot;">​</a></h3><p>使用方式：在 Halo 后台发布文章的时候，选择 <code>元数据</code> 新增元数据 key 值为 <code>unihalo_useVisitPwd</code>，填入您设置好的密码，如 <code>123456</code>，（<strong><em>注意：留空或者删除 unihalo_useVisitPwd 不会生效</em></strong>）如图所示：</p><p><img src="https://img.925i.cn/file/6bd6a7ccfc898cba5d3dd.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><p>在 <code>uni-halo</code> 应用内的文章详情页面的效果如下，您只需要输入您设置好的密码就可以正常访问了，如图所示：</p><p><img src="https://img.925i.cn/file/da9dfcde41aa350833bde.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><h3 id="_3-文章部分加密-unihalo-usevisitmorepwd" tabindex="-1">3. 文章部分加密：<code>unihalo_useVisitMorePwd</code> <a class="header-anchor" href="#_3-文章部分加密-unihalo-usevisitmorepwd" aria-label="Permalink to &quot;3. 文章部分加密：`unihalo_useVisitMorePwd`&quot;">​</a></h3><p>使用方式：在 Halo 后台发布文章的时候，选择 <code>元数据</code> 新增元数据 key 值为 <code>unihalo_useVisitMorePwd</code>，填入您设置好的密码，如 <code>123456</code>，（<strong><em>注意：留空或者删除 unihalo_useVisitMorePwd 不会生效</em></strong>）如图所示：</p><p><img src="https://img.925i.cn/file/550b6f275789722f36838.png" alt="图片" data-fancybox="gallery" loading="lazy"></p><p>在 <code>uni-halo</code> 应用内的文章详情页面的效果如下，您只需要点击解锁然后输入您设置好的密码就可以正常访问了，如图所示： <img src="https://img.925i.cn/file/dd4e2b0a7c42e3d6c04c9.png" alt="图片" data-fancybox="gallery" loading="lazy"><img src="https://img.925i.cn/file/51bb5f8da9dd0beca59de.png" alt="图片" data-fancybox="gallery" loading="lazy"></p>',21)),e(i),e(l)])}const _=d(s,[["render",r]]);export{f as __pageData,_ as default};
